// Setup in app root:
<ToasterProvider toaster={toaster}><App /><ToasterComponent /></ToasterProvider>

// In component:
const {add} = useToaster();
add({name: 'save-ok', title: 'Saved', theme: 'success', autoHiding: 3000});

const {add, remove} = useToaster();
add({name: 'save-success', title: 'Saved', theme: 'success', autoHiding: 3000});
remove('save-success');

const containerRef = React.useRef(null);
const {visibleCount, calculated} = useCollapseChildren({containerRef, gap: 8});
// render items.slice(0, visibleCount) + overflow button

const internalRef = React.useRef(null);
const mergedRef = useForkRef(forwardedRef, internalRef);
return <div ref={mergedRef} />;

const sentinelRef = React.useRef(null);
useIntersection({element: sentinelRef.current, onIntersect: loadMore});
return <div ref={sentinelRef} />;

const anchorRef = React.useRef(null);
const {activeItemIndex} = useListNavigation({items, anchorRef});
return <ul ref={anchorRef} tabIndex={0}>{items.map((item, i) => <li aria-selected={i === activeItemIndex}>{item.label}</li>)}</ul>;

const popupRef = React.useRef(null);
useOutsideClick({ref: popupRef, handler: () => setOpen(false)});
return <div ref={popupRef}>{children}</div>;

const ref = React.useRef(null);
useResizeObserver({ref, onResize: () => recalculate()});
return <div ref={ref}>{children}</div>;
